messages.content:
You are an interface derivation agent. Given a frozen Stage 1 decomposition, your task is to derive precise typed interfaces for each child.

RULES:
1. You MUST NOT add, delete, rename, or reorder children. The child list from Stage 1 is LOCKED.
2. You MUST NOT change any Stage 1 field (purpose, behavior, boundary, preconditions, postconditions, guarantees, composition_role).
3. Derive ONLY interface fields.
4. Separate parent-call parameters from internal leaf resource access.

REQUIRED INTERFACE CATEGORIES:
- call_inputs: Parameters the parent must pass when calling this child. Only these may appear in the Python signature.
- internal_leaf_accesses: Resources/data stores this child accesses inside its own implementation. These must NOT appear in the Python signature.
- outputs: Values returned by the child to the parent.
- signature: Python function signature built only from call_inputs.

DATAFLOW RULES:
- from_node and to_node must be either "parent" or an exact child name.
- Resource/store names such as raw_data, processed_data, channels, messages, orders, inventory, or payments must NOT appear as from_node/to_node.

OUTPUT FORMAT — Return valid JSON:
{
  "children": [
    {
      "name": "UNCHANGED from Stage 1",
      "purpose": "UNCHANGED",
      "behavior": "UNCHANGED",
      "boundary": {"in_scope": ["UNCHANGED"], "out_of_scope": ["UNCHANGED"]},
      "semantic_inputs": ["UNCHANGED"],
      "semantic_outputs": ["UNCHANGED"],
      "preconditions": ["UNCHANGED"],
      "postconditions": ["UNCHANGED"],
      "guarantees": ["UNCHANGED"],
      "composition_role": "UNCHANGED",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {"name": "param", "type": "dict", "description": "what parent passes", "source": "parent input | previous child output | constant"}
      ],
      "internal_leaf_accesses": [
        {"resource": "resource_name", "op": "read|write|read_write", "reason": "why this child needs the resource internally"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "what child returns", "consumer": "parent"}
      ],
      "signature": "def ChildName(param: type) -> return_type"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {"input_name": "child_name"},
    "parent_outputs_produced_by": {"output_name": "child_name"}
  },
  "dataflow_edges": [
    {"from_node": "parent | ChildName", "from_output": "output_name", "to_node": "ChildName | parent", "to_input": "input_name", "note": "why"}
  ],
  "interface_audit": {
    "identity_preservation_detail": "explain whether child names/order are preserved",
    "semantic_preservation_detail": "explain whether Stage1 semantics are unchanged",
    "call_signature_detail": "explain why signature contains only call_inputs",
    "internal_leaf_separation_detail": "explain why resources are not call params",
    "dataflow_schema_detail": "explain endpoint legality",
    "final_status": "ok | needs_attention"
  }
}

{
  "children": [
    {
      "name": "ParseCommand",
      "purpose": "Extract and validate the command field from the input JSON",
      "behavior": "Parse the input JSON to extract the 'command' field and validate it is one of the allowed commands (send, history, create_channel, join). Return the command and remaining payload.",
      "boundary": {
        "in_scope": [
          "JSON parsing",
          "command validation"
        ],
        "out_of_scope": [
          "executing the command",
          "data store access"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "Raw JSON input from parent",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "command",
          "description": "Validated command string",
          "consumer": "parent"
        },
        {
          "name": "payload",
          "description": "Remaining JSON fields after command extraction",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "Input is valid JSON"
      ],
      "postconditions": [
        "Command is one of the allowed values"
      ],
      "guarantees": [
        "Returns error if command is missing or invalid"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "SendMessage",
      "purpose": "Handle sending a message to a channel",
      "behavior": "Validate that the user is a member of the specified channel, then store the message in the messages data store with timestamp and user info.",
      "boundary": {
        "in_scope": [
          "message validation",
          "channel membership check",
          "message storage"
        ],
        "out_of_scope": [
          "command parsing",
          "history retrieval"
        ]
      },
      "semantic_inputs": [
        {
          "name": "payload",
          "description": "Contains channel, user, and message content",
          "source": "parent input (from ParseCommand)"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "User is member of the channel",
        "Message content is non-empty"
      ],
      "postconditions": [
        "Message is stored in messages data store"
      ],
      "guarantees": [
        "Returns error if user not in channel"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "GetHistory",
      "purpose": "Retrieve message history for a channel",
      "behavior": "Validate that the user is a member of the channel, then fetch the last 100 messages from the messages data store for that channel, ordered by timestamp.",
      "boundary": {
        "in_scope": [
          "channel membership check",
          "message retrieval",
          "limit enforcement"
        ],
        "out_of_scope": [
          "message sending",
          "channel creation"
        ]
      },
      "semantic_inputs": [
        {
          "name": "payload",
          "description": "Contains channel and user",
          "source": "parent input (from ParseCommand)"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "List of messages or error",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "User is member of the channel"
      ],
      "postconditions": [
        "Returns at most 100 messages"
      ],
      "guarantees": [
        "Returns error if user not in channel"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "CreateChannel",
      "purpose": "Create a new channel",
      "behavior": "Check that the channel name does not already exist, then create a new channel entry in the channels data store with the creator as the first member.",
      "boundary": {
        "in_scope": [
          "channel name uniqueness check",
          "channel creation",
          "initial membership"
        ],
        "out_of_scope": [
          "joining existing channels",
          "message operations"
        ]
      },
      "semantic_inputs": [
        {
          "name": "payload",
          "description": "Contains channel name and creator user",
          "source": "parent input (from ParseCommand)"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "Channel name does not already exist"
      ],
      "postconditions": [
        "Channel is created and creator is added as member"
      ],
      "guarantees": [
        "Returns error if channel already exists"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "JoinChannel",
      "purpose": "Add a user to an existing channel",
      "behavior": "Check that the channel exists and the user is not already a member, then add the user to the channel's member list in the channels data store.",
      "boundary": {
        "in_scope": [
          "channel existence check",
          "duplicate membership check",
          "membership update"
        ],
        "out_of_scope": [
          "channel creation",
          "message operations"
        ]
      },
      "semantic_inputs": [
        {
          "name": "payload",
          "description": "Contains channel name and user",
          "source": "parent input (from ParseCommand)"
        }
      ],
      "semantic_outputs": [
        {
          "name": "result",
          "description": "Success or error response",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "Channel exists",
        "User is not already a member"
      ],
      "postconditions": [
        "User is added to channel's member list"
      ],
      "guarantees": [
        "Returns error if channel does not exist or user already member"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    }
  ],
  "decomposition_rationale": "The parent ChatApp handles four distinct commands. ParseCommand extracts the command and delegates to the appropriate child function. Each child handles one command, ensuring single responsibility and no sibling calls. The parent orchestrates by calling ParseCommand first, then conditionally calling one of the four command handlers based on the parsed command.",
  "orchestration_model": "conditional",
  "dataflow_sketch": [
    {
      "from": "parent",
      "to": "ParseCommand",
      "data": "input JSON",
      "note": "Extract command and payload"
    },
    {
      "from": "ParseCommand",
      "to": "parent",
      "data": "command and payload",
      "note": "Return parsed data"
    },
    {
      "from": "parent",
      "to": "SendMessage",
      "data": "payload",
      "note": "If command is 'send'"
    },
    {
      "from": "parent",
      "to": "GetHistory",
      "data": "payload",
      "note": "If command is 'history'"
    },
    {
      "from": "parent",
      "to": "CreateChannel",
      "data": "payload",
      "note": "If command is 'create_channel'"
    },
    {
      "from": "parent",
      "to": "JoinChannel",
      "data": "payload",
      "note": "If command is 'join'"
    },
    {
      "from": "SendMessage",
      "to": "parent",
      "data": "result",
      "note": "Return success/error"
    },
    {
      "from": "GetHistory",
      "to": "parent",
      "data": "result",
      "note": "Return messages or error"
    },
    {
      "from": "CreateChannel",
      "to": "parent",
      "data": "result",
      "note": "Return success/error"
    },
    {
      "from": "JoinChannel",
      "to": "parent",
      "data": "result",
      "note": "Return success/error"
    }
  ]
}
